mbr.copysrc:
     /* =================================================================== */
     /*                                                                     */
     /*  Documentation:                                                     */
     /*                                                                     */
     /*  Utility . . . : EVENTF                                             */
     /*  Object  . . . : A_INSTALL  (PGM)                                   */
     /*  Source member : A_INSTALL                                          */
     /*  Source type . : CLLE                                               */
     /*  Description   : EVENTF - Installer                                 */
     /*  Author  . . . : Thomas Raddatz   <thomas.raddatz@tools400.de>      */
     /*                                                                     */
     /* =================================================================== */
     /*                                                                     */
     /*  This software is free software, you can redistribute it and/or     */
     /*  modify it under the terms of the GNU General Public License (GPL)  */
     /*  as published by the Free Software Foundation.                      */
     /*                                                                     */
     /*  See GNU General Public License for details.                        */
     /*          http://www.opensource.org                                  */
     /*          http://www.opensource.org/licenses/gpl-license.html        */
     /*                                                                     */
     /* =================================================================== */
     /*  History:                                                           */
     /*                                                                     */
     /*  Datum       Name          Änderung                                 */
     /*  ----------  ------------  ---------------------------------------  */
     /*                                                                     */
     /* =================================================================== */
     /*   >>PRE-COMPILER<<                                                  */
     /*     >>CRTCMD<<    CRTBNDCL  PGM(QTEMP/&OB) +                        */
     /*                             SRCFILE(&SL/&SF) SRCMBR(&SM);           */
     /*     >>IMPORTANT<<                                                   */
     /*       >>PARM<<    OPTION(*EVENTF);                                  */
     /*     >>END-IMPORTANT<<                                               */
     /*     >>EXECUTE<<                                                     */
     /*     >>CMD<<       CALL   PGM(QTEMP/A_INSTALL) +                     */
     /*                          PARM('*CURRENT' '&SF' '&LI' 'NO');         */
     /*     >>CMD<<       DLTPGM PGM(QTEMP/A_INSTALL);                      */
     /*   >>END-PRE-COMPILER<<                                              */
     /* =================================================================== */
             PGM        PARM(&TGTRLS &SRCFILE &TOLIB &CRTTSTPGM)

             DCL        VAR(&TGTRLS   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&SRCFILE  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&TOLIB    ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&CRTTSTPGM) TYPE(*CHAR) LEN(10)

             DCL        VAR(&SRCLIB   ) TYPE(*CHAR) LEN(10)

             CHGVAR     VAR(&SRCLIB) VALUE(&TOLIB   )

     /* -------------------------------- */
     /*  Delete old objects              */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/EVENTF1)
             MONMSG     MSGID(CPF2105)

             DLTSRVPGM  SRVPGM(&TOLIB/EVENTF)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/EVENTFT1)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/EVENTFT1)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/EVENTFT2)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/EVENTFT2)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/EVENTFT3)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/EVENTFT3)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/EVENTFT4)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/EVENTFT4)
             MONMSG     MSGID(CPF2105)

             RMVMSG     PGMQ(*SAME (*)) CLEAR(*ALL)

     /* -------------------------------- */
     /*  Create modules                  */
     /* -------------------------------- */
             CRTRPGMOD  MODULE(&TOLIB/EVENTF1) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          DBGVIEW(*LIST) TRUNCNBR(*NO) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(EVENTF1  ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create service programs         */
     /* -------------------------------- */
             CRTSRVPGM  SRVPGM(&TOLIB/EVENTF) +
                          MODULE(&TOLIB/EVENTF1) +
                          EXPORT(*SRCFILE) +
                          SRCFILE(&SRCLIB/&SRCFILE) +
                          SRCMBR(EVENTF) +
                          ACTGRP(*CALLER) +
                          DETAIL(*BASIC) +
                          BNDSRVPGM(&TOLIB/BASICS1) +
                          TEXT('Event File API') +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(EVENTF   ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create test programs            */
     /* -------------------------------- */
             IF         COND(&CRTTSTPGM *EQ 'YES') THEN(DO)
                CRTRPGMOD  MODULE(&TOLIB/EVENTFT1) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(EVENTFT1 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/EVENTFT1) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/BASICS1  +
                                       &TOLIB/EVENTF ) +
                             ACTGRP(*NEW) +
                             TGTRLS(&TGTRLS) +
                             DETAIL(*BASIC)
                DLTSPLF    FILE(EVENTFT1 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/EVENTFT1)

                CRTRPGMOD  MODULE(&TOLIB/EVENTFT2) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
               DLTSPLF    FILE(EVENTFT2 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/EVENTFT2) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/BASICS1  +
                                       &TOLIB/EVENTF ) +
                             ACTGRP(*NEW) +
                             TGTRLS(&TGTRLS) +
                             DETAIL(*BASIC)
                DLTSPLF    FILE(EVENTFT2 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/EVENTFT2)

                CRTRPGMOD  MODULE(&TOLIB/EVENTFT3) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(EVENTFT3 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/EVENTFT3) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/BASICS1  +
                                       &TOLIB/EVENTF ) +
                             ACTGRP(*NEW) +
                             TGTRLS(&TGTRLS) +
                             DETAIL(*BASIC)
                DLTSPLF    FILE(EVENTFT3 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/EVENTFT3)

                CRTRPGMOD  MODULE(&TOLIB/EVENTFT4) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(EVENTFT4 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/EVENTFT4) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/BASICS1  +
                                       &TOLIB/EVENTF ) +
                             ACTGRP(*NEW) +
                             TGTRLS(&TGTRLS) +
                             DETAIL(*BASIC)
                DLTSPLF    FILE(EVENTFT4 ) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/EVENTFT4)

             ENDDO

     /* -------------------------------- */
     /*  Delete obsolete objects         */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/EVENTF1)

             ENDPGM

**free
/if not defined(CEELIB)
/define CEELIB

// ---------------------------------------------------------------
//   Program or Procedure Call APIs
// ---------------------------------------------------------------

//  Condition token, used as feedback code
dcl-ds cee_fc_t qualified template;
  Condition_ID char(4) pos(1);
  MsgSev       int(5) pos(1);
  Msg_No       uns(5) pos(3);
  Flags        char(1) pos(5);
  Facility_ID  char(3) pos(6);
  I_S_Info     char(4) pos(9);
end-ds;

//  Retrieve Operational Descriptor Information (CEEDOD)
dcl-pr CEEDOD extproc('CEEDOD');
  i_posn     int(10) const;
  o_desctype int(10);
  o_datatype int(10);
  o_descinf1 int(10);
  o_descinf2 int(10);
  o_datalen  int(10);
  o_fc       char(12) options(*omit);
end-pr;

//  Reference fields for CEEDOD API
dcl-ds descInf_t qualified template;
  desctype int(10);
  datatype int(10);
  descinf1 int(10);
  descinf2 int(10);
  datalen  int(10);
end-ds;

//  Test for Omitted Argument (CEETSTA) API
dcl-pr CEETSTA extproc('CEETSTA');
  io_isPresent int(10);
  i_argNum     int(10) const;
  o_fc         char(12) options(*omit);
end-pr;

//  Get String Information (CEEGSI) API
dcl-pr CEEGSI extproc('CEEGSI');
  i_posn     int(10) const;
  o_datatype int(10);
  o_curlen   int(10);
  o_maxlen   int(10);
  o_fb       char(12) options(*omit);
end-pr;

//  Reference fields for CEEGSI API
dcl-ds strInf_t qualified template;
  datatype int(10);
  curlen   int(10);
  maxlen   int(10);
end-ds;

// ---------------------------------------------------------------
//   Math APIs
// ---------------------------------------------------------------

//  Logarithm base 10 (double float)
dcl-pr CEESDLG1 extproc('CEESDLG1');
  i_value  float(8) const;
  o_result float(8);
end-pr;

// ---------------------------------------------------------------
//   ILE CEE Date and Time APIs
// ---------------------------------------------------------------

//  Calculate Day of Week from Lilian Date (CEEDYWK) API
dcl-pr CEEDYWK opdesc extproc('CEEDYWK');
  i_lilian_date int(10) const;
  o_day_no      int(10);
  o_feedback    char(12) options(*omit);
end-pr;

//  Convert Lilian Date to Character Format (CEEDATE) API
dcl-pr CEEDATE opdesc extproc('CEEDATE');
  i_lilian_date int(10) const;
  i_date_format char(80) options(*varsize) const;
  o_char_date   char(80) options(*varsize);
  o_feedback    char(12) options(*omit);
end-pr;

//  Convert Date to Lilian Format (CEEDAYS) API
dcl-pr CEEDAYS opdesc extproc('CEEDAYS');
  i_char_date   char(80) options(*varsize) const;
  i_date_format char(80) options(*varsize) const;
  o_lilian_date int(10);
  o_feedback    char(12) options(*omit);
end-pr;

//  Convert Seconds to Character Timestamp (CEEDATM) API
dcl-pr CEEDATM opdesc extproc('CEEDATM');
  i_input_seconds    float(8) const;
  i_picture_string   char(80) options(*varsize) const;
  o_output_timestamp char(80) options(*varsize);
  o_feedback         char(12) options(*omit);
end-pr;

//  Get Offset from Universal Time Coordinated to Local Time (CEEUTCO) API
dcl-pr CEEUTCO extproc('CEEUTCO');
  o_offsethours   int(10);
  o_offsetminutes int(10);
  o_offsetseconds float(8);
  o_feedback      char(12) options(*nopass);
end-pr;

dcl-ds cee_utco_t qualified template;
  offhours int(10);
  offmins  int(10);
  offsecs  float(8);
end-ds;

//  Convert Timestamp to Number of Seconds (CEESECS) API
dcl-pr CEESECS extproc('CEESECS') opdesc;
  i_inTimestamp char(255) options(*varsize) const;
  i_inPicture   char(255) options(*varsize) const;
  o_outSeconds  float(8);
  o_outFC       char(12) options(*omit);
end-pr;

// ---------------------------------------------------------------
//   Activation Group and Control Flow APIs
// ---------------------------------------------------------------

//  Register Activation Group Exit Procedure (CEE4RAGE) API
dcl-pr CEE4RAGE extproc('CEE4RAGE');
  i_pProc pointer(*proc) const;
  o_fc    char(12) options(*omit);
end-pr;

dcl-c END_ACTGRP_CODE_EXCEPTION_MESSAGE x'40000000';
dcl-c END_ACTGRP_CODE_ABNORMAL_END x'00008000';
dcl-c END_ACTGRP_CODE_ACTGRP_IS_ENDING x'00004000';
dcl-c END_ACTGRP_CODE_INIT_BY_RCLACTGRP x'00002000';
dcl-c END_ACTGRP_CODE_INIT_BY_JOB_END x'00001000';
dcl-c END_ACTGRP_CODE_INIT_BY_EXIT_VERB x'00000800';
dcl-c END_ACTGRP_CODE_INIT_BY_FUNCTION_CHECK x'00000400';
dcl-c END_ACTGRP_CODE_INIT_BY_OUT_OF_SCOPE_JUMP x'00000200';

dcl-pr CEE4RAGE_user_exit extproc('CEE4RAGE_user_exit');
  i_ag_mark      uns(10) const;
  i_reason       uns(10) const;
  io_result_code uns(10);
  io_user_rc     int(10);
end-pr;

//  Register Call Stack Entry Termination User Exit Procedure (CEERTX)
dcl-pr CEERTX extproc('CEERTX');
  i_procPtr  pointer(*proc) const;
  i_rtxToken pointer options(*omit) const;
  o_fc       char(12) options(*omit);
end-pr;

dcl-pr CEERTX_user_exit extproc('CEERTX_user_exit');
  i_rtxToken pointer const;
end-pr;

//  Unregister Call Stack Entry Termination User Exit Procedure (CEEUTX)
dcl-pr CEEUTX extproc('CEEUTX');
  i_procPtr pointer(*proc) const;
  o_fc      char(12) options(*omit);
end-pr;

/endif

**free
/if not defined(COPYRIGHT_DSPEC)
ctl-opt copyright('V1.3.0 - 04.05.2026 - mailto: thomas.raddatz@tools400.de');
/eof
/endif
dcl-c EVENTF_VERSION '1.3.0';
dcl-c EVENTF_DATE '04.05.2026';

     /* ===================================================================== */
     /*  Events File API                                                      */
     /* ===================================================================== */
     /*  Author  :  Thomas Raddatz                                            */
     /*  Date    :  19.05.2013                                                */
     /*  E-mail  :  thomas.raddatz@Tools400.de                                */
     /*  Homepage:  www.tools400.de                                           */
     /* ===================================================================== */
     /* >>PRE-COMPILER<<                                                      */
     /*   >>CRTCMD<< CRTSRVPGM    SRVPGM(&LI/EVENTF);                         */
     /*   >>LINK<<                                                            */
     /*     >>PARM<< MODULE(+                                                 */
     /*                     &LI/EVENTF1   +                                   */
     /*                     );                                                */
     /*     >>PARM<< EXPORT(*SRCFILE);                                        */
     /*     >>PARM<<   SRCFILE(&SL/&SF);                                      */
     /*     >>PARM<<   SRCMBR(&SM);                                           */
     /*     >>PARM<< ACTGRP(*CALLER);                                         */
     /*     >>PARM<< ALWUPD(*YES);                                            */
     /*     >>PARM<< ALWLIBUPD(*YES);                                         */
     /*     >>PARM<< BNDSRVPGM(&LI/BASICS1);                                  */
     /*     >>PARM<< TEXT('Events File API');                                 */
     /*     >>PARM<< TGTRLS(V7R3M0  );                                        */
     /*     >>PARM<< DETAIL(*BASIC);                                          */
     /*   >>END-LINK<<                                                        */
     /*   >>EXECUTE<<                                                         */
     /* >>END-PRE-COMPILER<<                                                  */
     /* ===================================================================== */

STRPGMEXP PGMLVL(*CURRENT) SIGNATURE('Events_File_API')

  EXPORT SYMBOL('EVENTF1_Eventf_open')
  EXPORT SYMBOL('EVENTF1_Eventf_writeProcessor')
  EXPORT SYMBOL('EVENTF1_Eventf_writeFileID')
  EXPORT SYMBOL('EVENTF1_Eventf_writeFileEnd')
  EXPORT SYMBOL('EVENTF1_Eventf_writeError')
  EXPORT SYMBOL('EVENTF1_Eventf_close')

  /* New with 1.2.2 */
  EXPORT SYMBOL('EVENTF1_Eventf_openAppend')
  EXPORT SYMBOL('EVENTF1_Eventf_clear')

  /* New with 1.2.3 */
  EXPORT SYMBOL('EVENTF1_Eventf_copyFrom')
ENDPGMEXP

**free
/if defined(EVENTF_H)
/eof
/endif
/define EVENTF_H

// The Events File contains information that allows the editor to locate, in the
// source member, any tokens or lines that caused a message to be issued, and to
// relate messages that refer to expanded source to the corresponding position in
// a given source file. The Events File is meant to provide machine-readable
// information useful to certain classes of tools. The processor's listing file,
// by contrast, is meant to be read by humans. Since the Events File has a common
// format across all processors, tools will not have to write processor-specific
// code to obtain the information they need.

// Source: http://pic.dhe.ibm.com/infocenter/iadthelp/v8r5/index.jsp?
//         topic=%2Fcom.ibm.etools.iseries.rse.doc%2Ftopics%2Frevformat.html

// Timestamp Record
// This record indicates when the Events File was created, and allows an application
// to determine if the Events File is current. This record is always the first record
// in the Events File.
dcl-ds evf_timestamp qualified template;
  type        char(10) inz('TIMESTAMP');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  value       char(14) inz; // yyyymmddhhmmss
end-ds;

// Processor Record
// This record indicates that a new processor has been invoked.
// One will always follow the timestamp record in the Events File.
dcl-ds evf_processor qualified template;
  type        char(10) inz('PROCESSOR');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  output_id   char(3) inz('000');
  separator_3 char(1) inz;
  line_class  char(1) inz('1');
end-ds;

// File ID Record
// This record contains the full name of the source file processed
// and associates an integer with the file name.
// Usage:  result = %trimR(evf_file_id_1) + evf_file_id_2
dcl-ds evf_file_id_1 qualified template;
  type        char(10) inz('FILEID');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  source_id   char(3) inz('001');
  separator_3 char(1) inz;
  line        char(6) inz('000000');
  separator_4 char(1) inz;
  length      char(3) inz('000');
  separator_5 char(1) inz;
  filename    char(200) inz('Library___/File______(Member____)');
end-ds;

dcl-ds evf_file_id_2 qualified template;
  separator_6          char(1) inz;
  sourcefile_timestamp char(14) inz('YYYYMMDDHHMMSS');
  separator_7          char(1) inz;
  temp_flag            char(1) inz('0');
end-ds;

// File End Record
// This record indicates that an included file is ending.
dcl-ds evf_file_end qualified template;
  type        char(10) inz('FILEEND');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  file_id     char(3) inz('001');
  separator_3 char(1) inz;
  expansion   char(6) inz('000000');
end-ds;

// Error Information Record
// A record of this type contains information required to locate
// a token or line causing a message in the source file, as well
// as enough information to allow the message itself to be displayed.
dcl-ds evf_error qualified template;
  type           char(10) inz('ERROR');
  separator_1    char(1) inz;
  version        char(1) inz('0');
  separator_2    char(1) inz;
  file_id        char(3) inz('001');
  separator_3    char(1) inz;
  annot_class    char(1) inz('1');
  separator_4    char(1) inz;
  stmt_line      char(6) inz('000000');
  separator_5    char(1) inz;
  start_err_line char(6) inz('000000');
  separator_6    char(1) inz;
  token_start    char(3) inz('000');
  separator_7    char(1) inz;
  end_err_line   char(6) inz('000000');
  separator_8    char(1) inz;
  token_end      char(3) inz('000');
  separator_9    char(1) inz;
  msg_id         char(7) inz;
  separator_10   char(1) inz;
  msg_id         char(7) inz;
  separator_11   char(1) inz;
  sev_char       char(1) inz('E'); // I, W, E, S, or
  separator_12   char(1) inz;
  sev_num        char(2) inz('30');
  separator_13   char(1) inz;
  length         char(3) inz('000');
  separator_14   char(1) inz;
  msg            char(200) inz;
end-ds;

// Expansion Record
// This record contains information about expanded source lines
// due to a pre-processor.
dcl-ds evf_expansion qualified template;
  type              char(10) inz('EXPANSION');
  separator_1       char(1) inz;
  version           char(1) inz('0');
  separator_2       char(1) inz;
  input_file_id     char(3) inz('000');
  separator_3       char(1) inz;
  input_line_start  char(6) inz('000000');
  separator_4       char(1) inz;
  input_line_end    char(6) inz('000000');
  separator_5       char(1) inz;
  output_file_id    char(3) inz('000');
  separator_6       char(1) inz;
  output_line_start char(6) inz('000000');
  separator_7       char(1) inz;
  output_line_end   char(6) inz('000000');
  separator_8       char(1) inz;
end-ds;

// Program Record
// This record indicates a new program in the same source file
// is being compiled.
// Note: All ERROR records for a program must come after the
//       PROGRAM record for that program and before any PROGRAM
//       records for other programs.
dcl-ds evf_program qualified template;
  type        char(10) inz('PROGRAM');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  line        char(6) inz('000000');
end-ds;

// Map Define Record
// This record indicates that a macro is being defined.
dcl-ds evf_map_define qualified template;
  type        char(10) inz('MAPDEFINE');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  macro_id    char(3) inz('000');
  separator_3 char(1) inz;
  line        char(6) inz('000000');
  separator_4 char(1) inz;
  length      char(3) inz('000');
  separator_5 char(1) inz;
  macro_name  char(200) inz;
end-ds;

// Map Start Record
// This record indicates that source expansion is starting.
dcl-ds evf_map_start qualified template;
  type        char(10) inz('MAPSTART');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  macro_id    char(3) inz('000');
  separator_3 char(1) inz;
  line        char(6) inz('000000');
end-ds;

// Map End Record
// This record indicates that source expansion is complete.
dcl-ds evf_map_end qualified template;
  type        char(10) inz('MAPEND');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  macro_id    char(3) inz('000');
  separator_3 char(1) inz;
  line        char(6) inz('000000');
  separator_4 char(1) inz;
  expansion   char(6) inz('000000');
end-ds;

// Feedback Code Record
// This record indicates that source expansion is complete.
dcl-ds evf_feedback qualified template;
  type        char(10) inz('FEEDBACK');
  separator_1 char(1) inz;
  version     char(1) inz('0');
  separator_2 char(1) inz;
  return_code char(3) inz('0');
  separator_3 char(1) inz;
  reason_code char(3) inz('0');
end-ds;

**free
//===============================================================*
//  erstellt : 19.05.2013                                        *
//===============================================================*
//                                                               *
//  Kurzdokumentation :                                          *
//                                                               *
//  Rahmentestprogramm mit Protokollausgabe                      *
//  Thema:                                                       *
//     Event File API - Example 1 (short path names)             *
//                                                               *
//===============================================================*
// >>PRE-COMPILER<<                                              *
//   >>CRTCMD<< CRTRPGMOD    MODULE(&LI/&OB) +                   *
//                           SRCFILE(&SL/&SF) +                  *
//                           SRCMBR(&SM);                        *
//   >>COMPILE<<                                                 *
//     >>PARM<< TRUNCNBR(*NO);                                   *
//     >>PARM<< DBGVIEW(*LIST);                                  *
//     >>PARM<< OPTION(*EVENTF);                                 *
